import React, { useMemo, useState } from 'react';
import {
  Button,
  Input,
  Select,
  Modal,
  MoneyInput, dispatchAppToast,
  formatMoney,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
  type LocaleNumberFormatConfig,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { ExchangeRateDto } from '../../../services/master/models';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import {
  CatalogCompanyField,
  useCatalogListPaging,
  useCatalogTableBusy,
  CatalogListGrid,
  CatalogListHeaderFilters,
  CatalogListMasterLinPageLayout,
} from '../../../components/catalog';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import { selectPlaceholderClass } from '../../../utils/selectField';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-ty-gia';
const INIT_FORM_NAME = 'create-exchange-rate';
/** Tỷ giá quy đổi VND — format tiền (###.###,##) · không phải SL */
const RATE_MONEY_FORMAT: LocaleNumberFormatConfig = { maxDecimals: 2, decimalSeparator: ',' };
const RATE_TRANSFER_MONEY_FORMAT: LocaleNumberFormatConfig = { maxDecimals: 4, decimalSeparator: ',' };
const formatRateMoney = (value: number | null | undefined) => formatMoney(value, RATE_MONEY_FORMAT);
const formatRateTransferMoney = (value: number | null | undefined) => formatMoney(value, RATE_TRANSFER_MONEY_FORMAT);

type RateForm = {
  currencyCode: string;
  monthYear: string;
  buyRate?: number;
  sellRate?: number;
  transferRate?: number;
};

type FormErrors = Partial<Record<'currencyCode' | 'monthYear' | 'buyRate' | 'transferRate', string>>;

const isPositiveRate = (value?: number) => value != null && !Number.isNaN(value) && value > 0;

const TyGiaPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const { currencyOptions: foreignCurrencyOpts } = useVoucherInitData(INIT_FORM_NAME);
  const [currencyFilter, setCurrencyFilter] = useState('');
  const [items, setItems] = useState<ExchangeRateDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [form, setForm] = useState<RateForm>({
    currencyCode: '',
    monthYear: '',
    buyRate: undefined,
    sellRate: undefined,
    transferRate: undefined,
  });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);
  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();

  type RateGridRow = ExchangeRateDto & { code: string };
  const gridRows = useMemo<RateGridRow[]>(
    () => items.map(r => ({ ...r, code: r.currencyCode })),
    [items],
  );

  const selection = useCatalogListSelection({
    rows: gridRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const handleSearch = () => {
    pulseSearch(() => {
      resetPage();
      selection.clearSelection();
      setReloadKey(k => k + 1);
    });
  };
  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getExchangeRates({ currencyCode: currencyFilter || undefined, page, pageSize })
        .then(result => {
          if (!cancelled) {
            setItems(result.items);
            setTotalCount(result.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải tỷ giá', type: 'error' });
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [currencyFilter, page, pageSize, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.currencyCode?.trim()) next.currencyCode = 'Chọn ngoại tệ';
    if (!form.monthYear?.trim()) next.monthYear = 'Chọn tháng/năm';
    if (!isPositiveRate(form.buyRate)) next.buyRate = 'Nhập tỷ giá mua vào';
    if (!isPositiveRate(form.transferRate)) next.transferRate = 'Nhập tỷ giá chuyển khoản';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setForm({
      currencyCode: currencyFilter || String(foreignCurrencyOpts[0]?.value ?? ''),
      monthYear: new Date().toISOString().slice(0, 7),
      buyRate: undefined,
      sellRate: undefined,
      transferRate: undefined,
    });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    const [yearStr, monthStr] = form.monthYear.split('-');
    const month = Number(monthStr);
    const year = Number(yearStr);
    setSaving(true);
    try {
      await masterService.createExchangeRate({
        currencyCode: normalizeCode(form.currencyCode),
        month,
        year,
        buyRate: form.buyRate!,
        sellRate: isPositiveRate(form.sellRate) ? form.sellRate : undefined,
        transferRate: form.transferRate!,
      });
      markClean();
      dispatchAppToast(dispatch, { message: 'Tạo tỷ giá thành công', type: 'success' });
      setModalOpen(false);
      resetPage();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleBatchDelete = async (_mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.map(r => r.id)
        : [...selection.selectedIds];
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    await Promise.all(ids.map(id => masterService.deleteExchangeRate(id)));
    dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} tỷ giá`, type: 'success' });
    refresh();
  };

  return (
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={gridRows}
        onAdd={openAdd}
        onEdit={() => {}}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setPage(p); selection.clearSelection(); }}
        onPageSizeChange={setPageSize}
        showTableLoading={showTableLoading}
        header={{ title: 'Tỷ giá ngoại tệ', titleIconClass: 'fas fa-exchange-alt' }}
        listTitle="Danh sách tỷ giá"
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-currencyFilter`}>
              <Select
                value={currencyFilter}
                placeholder="Tất cả ngoại tệ"
                className={selectPlaceholderClass(currencyFilter)}
                onChange={e => {
                  setCurrencyFilter(e.target.value);
                  resetPage();
                  selection.clearSelection();
                }}
                options={foreignCurrencyOpts}
              />
            </div>
            <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} showSearch={false} hideRefresh />
          </CatalogListHeaderFilters>
        )}
        extraModals={<LeaveConfirmModal {...leaveConfirmModalProps} />}
      >
        {items.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : (
          <CatalogListGrid
            testIdPrefix={TEST_ID}
            rows={gridRows}
            page={page}
            pageSize={pageSize}
            selection={selection}
            getRowId={r => r.id}
            headerCells={(
              <>
                <th>Ngoại tệ</th>
                <th>Tháng/Năm</th>
                <th className={styles.colRight}>Mua vào</th>
                <th className={styles.colRight}>Bán ra</th>
                <th className={styles.colRight}>Chuyển khoản</th>
              </>
            )}
            renderRow={r => (
              <>
                <td><code>{r.currencyCode}</code></td>
                <td>{r.month}/{r.year}</td>
                <td className={styles.colRight}>{formatRateMoney(r.buyRate)}</td>
                <td className={styles.colRight}>{formatRateMoney(r.sellRate)}</td>
                <td className={styles.colRight}>{formatRateTransferMoney(r.transferRate)}</td>
              </>
            )}
          />
        )}
      </CatalogListMasterLinPageLayout>

      <Modal isOpen={modalOpen} onClose={closeFormModal} title="Thêm tỷ giá">
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-currencyCode`}>
              <label className={styles.label}>Ngoại tệ *</label>
              <Select
                value={form.currencyCode}
                required
                placeholder="— Chọn ngoại tệ —"
                className={selectPlaceholderClass(form.currencyCode)}
                error={errors.currencyCode}
                onChange={e => {
                  markDirty();
                  clearFieldError('currencyCode');
                  setForm(f => ({ ...f, currencyCode: normalizeCode(e.target.value) }));
                }}
                options={foreignCurrencyOpts}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-monthYear`}>
              <label className={styles.label}>Tháng/Năm *</label>
              <Input
                type="month"
                value={form.monthYear}
                error={errors.monthYear}
                onChange={e => {
                  markDirty();
                  clearFieldError('monthYear');
                  setForm(f => ({ ...f, monthYear: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-buyRate`}>
              <label className={styles.label}>Tỷ giá mua vào *</label>
              <MoneyInput
                value={form.buyRate ?? 0}
                error={errors.buyRate}
                format={RATE_MONEY_FORMAT}
                onChange={v => {
                  markDirty();
                  clearFieldError('buyRate');
                  setForm(f => ({ ...f, buyRate: v > 0 ? v : undefined }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-sellRate`}>
              <label className={styles.label}>Tỷ giá bán ra</label>
              <MoneyInput
                value={form.sellRate ?? 0}
                format={RATE_MONEY_FORMAT}
                onChange={v => {
                  markDirty();
                  setForm(f => ({ ...f, sellRate: v > 0 ? v : undefined }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-transferRate`}>
              <label className={styles.label}>Tỷ giá chuyển khoản *</label>
              <MoneyInput
                value={form.transferRate ?? 0}
                error={errors.transferRate}
                format={RATE_TRANSFER_MONEY_FORMAT}
                onChange={v => {
                  markDirty();
                  clearFieldError('transferRate');
                  setForm(f => ({ ...f, transferRate: v > 0 ? v : undefined }));
                }}
              />
            </div>
          </div>
          <CatalogCompanyField
            testIdPrefix={TEST_ID}
            companyName={sessionCompanyName}
          />
          <div className={styles.modalActions}>
            <Button variant="secondary" onClick={closeFormModal}>Hủy</Button>
            <Button variant="primary" onClick={handleSave} disabled={saving} data-testid={`${TEST_ID}-save-btn`}>
              {saving ? 'Đang lưu...' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>
    </>
  );
};

export default TyGiaPage;
